// Refresh exitoso — loguear stats
const body = $input.first().json.body || {};
const stats = body.stats || {};
console.log(`[AgentKit] Refresh OK — total: ${stats.total}, nuevas: ${stats.nuevas}, removidas: ${stats.removidas}`);
return $input.all();

// Refresh fallido — loguear error
const statusCode = $input.first().json.statusCode || 'unknown';
const body = $input.first().json.body || {};
console.error(`[AgentKit] Refresh FALLIDO — status: ${statusCode}, error: ${JSON.stringify(body)}`);
